{action_set_definitions}: {
  "get_environment_component": {
    "description": "Retrieves a specific component of the environment state to allow the Agent to observe the current environment values.",
    "parameters": {
      "type": "object",
      "properties": {
        "component_name": {
          "type": "string",
          "enum": [
            "contract_body",
            "risk_register",
            "checklist_status",
            "review_metadata",
            "current_phase"
          ],
          "description": "The specific state field to retrieve."
        }
      },
      "required": [
        "component_name"
      ]
    },
    "example_output": {
      "content": "raw_text_or_object_data"
    }
  },
  "search_contract_clauses": {
    "description": "Searches the contract body for specific terminology, clauses, or sections.",
    "parameters": {
      "type": "object",
      "properties": {
        "query": {
          "type": "string",
          "description": "The keyword or provision title to search for (e.g., 'Mesh Topology')."
        }
      },
      "required": [
        "query"
      ]
    },
    "example_output": {
      "matches": [
        {
          "clause_text": "Clause 4.1: Change of Control...",
          "section_id": "4.1"
        }
      ]
    }
  },
  "update_risk_register": {
    "description": "Adds a legal hazard or breach status to the risk register.",
    "parameters": {
      "type": "object",
      "properties": {
        "clause_reference": {
          "type": "string",
          "description": "The specific clause identifier or section affected."
        },
        "risk_level": {
          "type": "string",
          "enum": [
            "Low",
            "Medium",
            "High",
            "Critical"
          ],
          "description": "The severity of the risk."
        },
        "description": {
          "type": "string",
          "description": "A detailed explanation of why the party is in breach or the nature of the legal hazard."
        }
      },
      "required": [
        "clause_reference",
        "risk_level",
        "description"
      ]
    },
    "example_output": {
      "status": "entry_added",
      "entry_id": 101
    }
  },
  "update_checklist": {
    "description": "Updates the fulfillment status of specific requirements in the checklist.",
    "parameters": {
      "type": "object",
      "properties": {
        "requirement_name": {
          "type": "string",
          "description": "The name of the requirement to update (e.g., 'EcoPower Joinder')."
        },
        "is_fulfilled": {
          "type": "boolean",
          "description": "The new status of the requirement."
        }
      },
      "required": [
        "requirement_name",
        "is_fulfilled"
      ]
    },
    "example_output": {
      "status": "updated"
    }
  },
  "transition_phase": {
    "description": "Moves the environment state to a new operational phase.",
    "parameters": {
      "type": "object",
      "properties": {
        "new_phase": {
          "type": "string",
          "description": "The name of the target phase (e.g., 'risk_mitigation')."
        }
      },
      "required": [
        "new_phase"
      ]
    },
    "example_output": {
      "current_phase": "risk_mitigation"
    }
  }
}
